using System; using System.Collections.Generic; using System.IO; using System.Text.Json; using BepInEx; using ProjectM; using Stunlock.Core; namespace VAutomationCore.Core.Api { public static class PrefabAliasRegistry { private static readonly Dictionary<string, string> AliasToPrefab = new(StringComparer.OrdinalIgnoreCase); private static bool _initialized; public static void Initialize() { if (_initialized) return; RegisterDefaultAliases(); _initialized = true; } private static void RegisterDefaultAliases() { var defaults = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase) { { "Spell_VeilOfBlood", "AB_Vampire_VeilOfBlood_Group" }, { "Spell_VeilOfChaos", "AB_Vampire_VeilOfChaos_Group" }, { "Spell_VeilOfFrost", "AB_Vampire_VeilOfFrost_Group" }, { "Spell_VeilOfBones", "AB_Vampire_VeilOfBones_AbilityGroup" }, { "Spell_BloodRite", "AB_Blood_BloodRite_AbilityGroup" }, { "VeilOfBlood", "AB_Vampire_VeilOfBlood_Group" }, { "VeilOfChaos", "AB_Vampire_VeilOfChaos_Group" }, { "VeilOfFrost", "AB_Vampire_VeilOfFrost_Group" }, { "VeilOfBones", "AB_Vampire_VeilOfBones_AbilityGroup" }, { "BloodRite", "AB_Blood_BloodRite_AbilityGroup" }, }; foreach (var kvp in defaults) AliasToPrefab[kvp.Key] = kvp.Value; } public static bool Register(string alias, string prefabName, bool replace = true) { if (string.IsNullOrWhiteSpace(alias) || string.IsNullOrWhiteSpace(prefabName)) return false; alias = alias.Trim(); prefabName = prefabName.Trim(); if (replace || !AliasToPrefab.ContainsKey(alias)) { AliasToPrefab[alias] = prefabName; return true; } return false; } public static bool TryResolve(string alias, out string prefabName) { if (!_initialized) Initialize(); prefabName = string.Empty; if (string.IsNullOrWhiteSpace(alias)) return false; return AliasToPrefab.TryGetValue(alias.Trim(), out prefabName); } public static IReadOnlyDictionary<string, string> GetAll() { if (!_initialized) Initialize(); return new Dictionary<string, string>(AliasToPrefab, StringComparer.OrdinalIgnoreCase); } } }